const express = require('express');
const https   = require('https');
const app     = express();
const PORT    = process.env.PORT || 8080;
const HOST    = '0.0.0.0';
const TRADIER_TOKEN = process.env.TRADIER_TOKEN || '';

// ── CORS ──────────────────────────────────────────────────────────────────────
app.use((req, res, next) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') return res.sendStatus(200);
  next();
});

// ── Embedded screener HTML ────────────────────────────────────────────────────
const SCREENER_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>MA Cross + VWAP Screener</title>\n<style>\n*{box-sizing:border-box;margin:0;padding:0}\nbody{background:#0f0f12;color:#ffffff;font-family:'Courier New',monospace;padding:16px;min-height:100vh;font-weight:600}\n.app{max-width:1150px;margin:0 auto}\n.topbar{display:flex;align-items:center;justify-content:space-between;margin-bottom:1rem;flex-wrap:wrap;gap:8px;padding-bottom:12px;border-bottom:1px solid #333}\n.brand{font-size:17px;font-weight:800;letter-spacing:.12em;color:#fff}\n.brand span{color:#4d8adb}\n.live-dot{width:8px;height:8px;border-radius:50%;background:#4db84d;display:inline-block;margin-right:6px;animation:blink 2s infinite}\n.sim-dot{width:8px;height:8px;border-radius:50%;background:#db9a4d;display:inline-block;margin-right:6px}\n@keyframes blink{0%,100%{opacity:1}50%{opacity:.3}}\n.status-row{display:flex;align-items:center;gap:8px;flex-wrap:wrap}\n.status{font-size:12px;color:#fff;display:flex;align-items:center;font-weight:700}\n.btn{font-size:12px;padding:6px 14px;border-radius:20px;border:1px solid #444;cursor:pointer;background:transparent;color:#fff;font-family:'Courier New',monospace;letter-spacing:.04em;transition:all .15s;font-weight:700}\n.btn:hover{background:#1e1e26;border-color:#888}\n.btn.primary{background:#4d8adb;color:#fff;border-color:#4d8adb;font-weight:800}\n.btn.sim{background:rgba(219,154,77,.2);color:#ffba5c;border-color:rgba(219,154,77,.5);font-weight:700}\n.sound-tog{display:flex;align-items:center;gap:6px;font-size:12px;color:#fff;cursor:pointer;font-weight:700}\n.mode-badge{font-size:10px;padding:3px 9px;border-radius:10px;letter-spacing:.05em;font-weight:800}\n.mode-live{background:rgba(77,184,77,.2);color:#5aff5a;border:1px solid rgba(77,184,77,.4)}\n.mode-sim{background:rgba(219,154,77,.2);color:#ffba5c;border:1px solid rgba(219,154,77,.4)}\n.tf-bar{display:flex;align-items:center;gap:6px;margin-bottom:1rem;flex-wrap:wrap;padding:10px 14px;background:#13131a;border:1px solid #2a2a3a;border-radius:10px}\n.tf-label{font-size:11px;color:#fff;letter-spacing:.07em;text-transform:uppercase;margin-right:4px;white-space:nowrap;font-weight:800}\n.tf-btn{font-size:12px;padding:5px 14px;border-radius:16px;border:1px solid #333;cursor:pointer;background:transparent;color:#bbb;font-family:'Courier New',monospace;transition:all .15s;white-space:nowrap;font-weight:700}\n.tf-btn:hover{border-color:#888;color:#fff}\n.tf-btn.active{background:#1e2d3e;color:#5aaeff;border-color:#4d8adb;font-weight:800}\n.tf-desc{font-size:11px;color:#ccc;margin-left:auto;text-align:right;line-height:1.5;font-weight:600}\n.info-bar{background:#16161e;border:1px solid #333;border-radius:8px;padding:10px 14px;font-size:12px;color:#fff;margin-bottom:1rem;line-height:1.7;font-weight:600}\n.tabs{display:flex;margin-bottom:1rem;border-bottom:1px solid #333}\n.tab{font-size:12px;padding:8px 16px;cursor:pointer;color:#bbb;letter-spacing:.05em;border-bottom:2px solid transparent;margin-bottom:-1px;transition:color .15s;font-weight:700}\n.tab.active{color:#fff;border-bottom-color:#4d8adb;font-weight:800}\n.tab:hover{color:#fff}\n.stats-row{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:8px;margin-bottom:1rem}\n.stat{background:#16161e;border-radius:8px;padding:10px 12px;border:1px solid #2a2a3a}\n.stat-lbl{font-size:10px;color:#ccc;letter-spacing:.07em;text-transform:uppercase;margin-bottom:4px;font-weight:700}\n.stat-val{font-size:22px;font-weight:800}\n.green{color:#5aff7a}.red{color:#ff5a5a}.blue{color:#5aaeff}.amber{color:#ffba5c}.purple{color:#c0a0ff}\n.filters{display:flex;gap:6px;flex-wrap:wrap;margin-bottom:.75rem}\n.pill{font-size:12px;padding:5px 12px;border-radius:20px;border:1px solid #333;cursor:pointer;background:transparent;color:#ccc;transition:all .15s;font-weight:700}\n.pill:hover{border-color:#888;color:#fff}\n.pill.a-all{background:#1e1e2a;color:#fff;border-color:#666;font-weight:800}\n.pill.a-bull{background:rgba(77,184,77,.15);color:#5aff7a;border-color:rgba(77,184,77,.5);font-weight:800}\n.pill.a-bear{background:rgba(255,90,90,.15);color:#ff5a5a;border-color:rgba(255,90,90,.5);font-weight:800}\n.pill.a-conf{background:rgba(192,160,255,.15);color:#c0a0ff;border-color:rgba(192,160,255,.5);font-weight:800}\n.tbl-wrap{border:1px solid #2a2a3a;border-radius:10px;overflow:hidden;margin-bottom:1rem}\ntable{width:100%;border-collapse:collapse;font-size:12px;table-layout:fixed}\nthead{background:#14141c}\nthead th{padding:9px 10px;text-align:left;font-size:10px;letter-spacing:.07em;text-transform:uppercase;color:#fff;font-weight:800;border-bottom:1px solid #2a2a3a;cursor:pointer;user-select:none;white-space:nowrap}\nthead th:hover{color:#5aaeff}\ntbody tr{border-bottom:1px solid #1e1e2a;cursor:pointer;transition:background .1s}\ntbody tr:last-child{border-bottom:none}\ntbody tr:hover{background:#1a1a24}\ntd{padding:9px 10px;color:#fff;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;font-weight:600}\n.tk{font-weight:800;letter-spacing:.06em;font-size:14px;color:#fff}\n.sig-bull{color:#5aff7a;font-size:10px;padding:3px 8px;border-radius:10px;background:rgba(77,184,77,.15);border:1px solid rgba(77,184,77,.4);font-weight:800}\n.sig-bear{color:#ff5a5a;font-size:10px;padding:3px 8px;border-radius:10px;background:rgba(255,90,90,.15);border:1px solid rgba(255,90,90,.4);font-weight:800}\n.tf-tag{font-size:10px;padding:2px 7px;border-radius:8px;background:#1e2d3e;color:#5aaeff;border:1px solid #2a4060;margin-left:4px;font-weight:800}\n.conf-high{color:#c0a0ff;font-size:10px;padding:3px 8px;border-radius:10px;background:rgba(192,160,255,.15);border:1px solid rgba(192,160,255,.4);font-weight:800}\n.conf-low{color:#aaa;font-size:10px;padding:3px 8px;border-radius:10px;background:#1a1a22;border:1px solid #333;font-weight:700}\n.stars{color:#ffba5c;letter-spacing:-1px;font-size:13px;font-weight:800}\n.chart-panel{border:1px solid #2a2a3a;border-radius:10px;padding:1rem;margin-bottom:1rem;background:#0d0d10}\n.chart-hdr{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:.75rem;flex-wrap:wrap;gap:8px}\n.chart-tk{font-size:18px;font-weight:800;letter-spacing:.08em;color:#fff}\n.chart-sub{font-size:12px;color:#ddd;margin-top:3px;font-weight:600}\n.tf-context{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:.75rem}\n.tf-ctx-item{font-size:11px;padding:4px 10px;border-radius:8px;display:flex;align-items:center;gap:5px;font-weight:700}\n.tf-ctx-bull{background:rgba(77,184,77,.1);border:1px solid rgba(77,184,77,.3);color:#5aff7a}\n.tf-ctx-bear{background:rgba(255,90,90,.1);border:1px solid rgba(255,90,90,.3);color:#ff5a5a}\n.tf-ctx-none{background:#13131a;border:1px solid #2a2a3a;color:#888}\n.tf-ctx-label{font-size:10px;color:#fff;margin-right:2px;font-weight:800}\n.conviction-card{border:1px solid #2a2a3a;border-radius:8px;padding:10px 12px;margin-bottom:.75rem;display:grid;grid-template-columns:repeat(7,minmax(0,1fr));gap:6px;background:#0f0f15}\n.cv-item{text-align:center}\n.cv-lbl{font-size:9px;color:#ddd;letter-spacing:.05em;text-transform:uppercase;margin-bottom:3px;font-weight:700}\n.cv-val{font-size:15px;font-weight:800}\n.score-bar-wrap{margin-bottom:.75rem}\n.score-bar-lbl{display:flex;justify-content:space-between;font-size:11px;color:#fff;margin-bottom:5px;font-weight:700}\n.score-bar-bg{height:7px;border-radius:4px;background:#1a1a22}\n.score-bar-fill{height:7px;border-radius:4px;transition:width .4s}\n.leg{display:flex;gap:14px;font-size:11px;color:#fff;flex-wrap:wrap;font-weight:700}\n.leg span{display:flex;align-items:center;gap:5px}\n.leg-line{width:18px;height:2px;border-radius:1px;display:inline-block}\n.alert-section{border:1px solid #2a2a3a;border-radius:10px;padding:1rem;margin-bottom:1rem;background:#0d0d10}\n.alert-hdr{font-size:13px;font-weight:800;margin-bottom:.75rem;display:flex;justify-content:space-between;align-items:center;color:#fff}\n.al-form{display:flex;flex-wrap:wrap;gap:8px;align-items:center;margin-bottom:.75rem}\n.al-form input,.al-form select{font-size:12px;font-family:'Courier New',monospace;height:34px;padding:0 10px;background:#16161e;border:1px solid #333;color:#fff;border-radius:6px;font-weight:700}\n.al-form input::placeholder{color:#999}\n.al-form input:focus,.al-form select:focus{outline:none;border-color:#4d8adb}\n.al-form input[type=text]{width:80px;text-transform:uppercase}\n.al-form input[type=number]{width:90px}\n.al-form select{min-width:190px}\n.alert-list{display:flex;flex-direction:column;gap:6px}\n.al-item{display:flex;align-items:center;gap:8px;font-size:12px;padding:8px 12px;border-radius:8px;background:#14141c;border:1px solid #2a2a3a;flex-wrap:wrap;font-weight:700;color:#fff}\n.al-item.triggered{background:rgba(219,154,77,.1);border-color:rgba(219,154,77,.4)}\n.notif-area{display:flex;flex-direction:column;gap:6px}\n.notif{padding:9px 14px;border-radius:8px;font-size:12px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:4px;font-weight:700}\n.notif.bull{background:rgba(77,184,77,.1);border:1px solid rgba(77,184,77,.3);color:#5aff7a}\n.notif.bear{background:rgba(255,90,90,.1);border:1px solid rgba(255,90,90,.3);color:#ff5a5a}\n.notif.price{background:rgba(219,154,77,.1);border:1px solid rgba(219,154,77,.3);color:#ffba5c}\n.notif-time{font-size:10px;opacity:.8}\n.empty{padding:2rem;text-align:center;color:#aaa;font-size:13px;font-weight:700}\n/* \u2500\u2500 OPTIONS FLOW \u2500\u2500 */\n.flow-panel{border:1px solid #2a2a3a;border-radius:10px;padding:1rem;margin-bottom:1rem;background:#0d0d10}\n.flow-hdr{font-size:13px;font-weight:800;color:#fff;margin-bottom:.75rem;display:flex;justify-content:space-between;align-items:center}\n.flow-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:8px;margin-bottom:.75rem}\n.flow-stat{background:#16161e;border-radius:8px;padding:8px 10px;border:1px solid #2a2a3a;text-align:center}\n.flow-lbl{font-size:9px;color:#ccc;letter-spacing:.06em;text-transform:uppercase;margin-bottom:3px;font-weight:700}\n.flow-val{font-size:16px;font-weight:800}\n.flow-bull{color:#5aff7a}.flow-bear{color:#ff5a5a}.flow-neut{color:#ffba5c}\n.sentiment-bar{display:flex;align-items:center;gap:8px;margin-bottom:.75rem;font-size:11px;font-weight:700}\n.sent-label{color:#fff;min-width:80px}\n.sent-track{flex:1;height:8px;background:#1a1a22;border-radius:4px;overflow:hidden}\n.sent-fill{height:8px;border-radius:4px;transition:width .4s}\n.unusual-table{width:100%;border-collapse:collapse;font-size:11px}\n.unusual-table th{padding:6px 8px;text-align:left;font-size:9px;letter-spacing:.06em;text-transform:uppercase;color:#aaa;font-weight:700;border-bottom:1px solid #2a2a3a}\n.unusual-table td{padding:6px 8px;border-bottom:1px solid #1a1a22;font-weight:600}\n.unusual-table tr:last-child td{border-bottom:none}\n.flow-loading{text-align:center;color:#aaa;padding:1rem;font-size:12px;font-weight:700}\n.pc-bull{color:#5aff7a}.pc-bear{color:#ff5a5a}.pc-neut{color:#ffba5c}\n.opt-tag{font-size:9px;padding:2px 6px;border-radius:6px;font-weight:800}\n.opt-call{background:rgba(77,184,77,.15);color:#5aff7a;border:1px solid rgba(77,184,77,.3)}\n.opt-put{background:rgba(255,90,90,.15);color:#ff5a5a;border:1px solid rgba(255,90,90,.3)}\n/* \u2500\u2500 STRAT \u2500\u2500 */\n.strat-badge{font-size:10px;padding:2px 7px;border-radius:8px;font-weight:800;white-space:nowrap}\n.strat-2u{background:rgba(77,184,77,.15);color:#5aff7a;border:1px solid rgba(77,184,77,.35)}\n.strat-2d{background:rgba(255,90,90,.15);color:#ff5a5a;border:1px solid rgba(255,90,90,.35)}\n.strat-3{background:rgba(219,154,77,.15);color:#ffba5c;border:1px solid rgba(219,154,77,.35)}\n.strat-1{background:#1a1a22;color:#888;border:1px solid #333}\n.strat-ok{box-shadow:0 0 6px rgba(77,184,77,.4)}\n.strat-conflict{box-shadow:0 0 6px rgba(255,90,90,.3)}\n/* \u2500\u2500 TOP PICKS \u2500\u2500 */\n.picks-overlay{position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.85);z-index:1000;display:flex;align-items:center;justify-content:center;padding:16px}\n.picks-modal{background:#0f0f15;border:1px solid #2a2a3a;border-radius:14px;width:100%;max-width:680px;max-height:90vh;overflow-y:auto;padding:1.25rem}\n.picks-hdr{display:flex;justify-content:space-between;align-items:center;margin-bottom:1rem}\n.picks-title{font-size:16px;font-weight:800;color:#fff;letter-spacing:.06em}\n.picks-sub{font-size:11px;color:#aaa;font-weight:600;margin-top:2px}\n.picks-close{font-size:18px;cursor:pointer;color:#888;background:none;border:none;font-family:'Courier New',monospace;padding:0 4px}\n.picks-close:hover{color:#fff}\n.pick-card{background:#16161e;border:1px solid #2a2a3a;border-radius:10px;padding:12px 14px;margin-bottom:10px;cursor:pointer;transition:border-color .15s}\n.pick-card:hover{border-color:#4d8adb}\n.pick-card.rank-1{border-color:rgba(219,154,77,.5);background:rgba(219,154,77,.05)}\n.pick-card.rank-2{border-color:rgba(192,160,255,.4);background:rgba(192,160,255,.04)}\n.pick-card.rank-3{border-color:rgba(90,174,255,.35);background:rgba(90,174,255,.04)}\n.pick-row1{display:flex;align-items:center;gap:10px;margin-bottom:6px;flex-wrap:wrap}\n.pick-rank{font-size:18px;font-weight:800;min-width:28px}\n.rank-1 .pick-rank{color:#ffba5c}\n.rank-2 .pick-rank{color:#c0a0ff}\n.rank-3 .pick-rank{color:#5aaeff}\n.pick-ticker{font-size:18px;font-weight:800;color:#fff;letter-spacing:.06em}\n.pick-price{font-size:13px;color:#aaa;font-weight:600}\n.pick-signal-badge{font-size:10px;padding:3px 8px;border-radius:10px;font-weight:800}\n.pick-tf{font-size:10px;padding:2px 7px;border-radius:8px;background:#1e2d3e;color:#5aaeff;border:1px solid #2a4060;font-weight:800}\n.pick-score-bar{height:5px;border-radius:3px;background:#1a1a22;margin-bottom:6px}\n.pick-score-fill{height:5px;border-radius:3px}\n.pick-indicators{display:flex;gap:6px;flex-wrap:wrap}\n.pick-ind{font-size:10px;padding:2px 7px;border-radius:6px;font-weight:700}\n.ind-pass{background:rgba(77,184,77,.12);color:#5aff7a;border:1px solid rgba(77,184,77,.25)}\n.ind-fail{background:#1a1a22;color:#555;border:1px solid #2a2a36}\n.pick-reason{font-size:11px;color:#ccc;font-weight:600;margin-top:6px;line-height:1.5}\n.picks-empty{text-align:center;padding:2rem;color:#aaa;font-size:13px;font-weight:700}\n.picks-loading{text-align:center;padding:2rem;color:#5aaeff;font-size:13px;font-weight:700}\n.picks-count{font-size:11px;color:#888;font-weight:600}\n/* \u2500\u2500 MARKET HOURS + AUTO REFRESH \u2500\u2500 */\n.mkt-open{font-size:10px;padding:3px 8px;border-radius:10px;background:rgba(77,184,77,.15);color:#5aff7a;border:1px solid rgba(77,184,77,.3);font-weight:800}\n.mkt-closed{font-size:10px;padding:3px 8px;border-radius:10px;background:rgba(255,90,90,.1);color:#ff8a8a;border:1px solid rgba(255,90,90,.25);font-weight:800}\n.mkt-pre{font-size:10px;padding:3px 8px;border-radius:10px;background:rgba(219,154,77,.15);color:#ffba5c;border:1px solid rgba(219,154,77,.3);font-weight:800}\n.refresh-bar{display:flex;align-items:center;gap:10px;padding:5px 14px;background:#0d0d10;border-bottom:1px solid #1e1e2a;font-size:11px;color:#aaa;font-weight:600;flex-wrap:wrap}\n.refresh-progress{flex:1;height:3px;background:#1a1a22;border-radius:2px;max-width:140px}\n.refresh-fill{height:3px;border-radius:2px;background:#4d8adb;transition:width 1s linear}\n@media(max-width:640px){\n  .stats-row{grid-template-columns:repeat(3,minmax(0,1fr))}\n  .stats-row .stat:nth-child(4),.stats-row .stat:nth-child(5){display:none}\n  td:nth-child(3),th:nth-child(3),td:nth-child(8),th:nth-child(8){display:none}\n  .conviction-card{grid-template-columns:repeat(3,minmax(0,1fr))}\n  .tf-desc{display:none}\n}\n</style>\n</head>\n<body>\n<div class=\"app\">\n\n  <div class=\"topbar\">\n    <div class=\"brand\">MA<span>CROSS</span> + VWAP + OPTIONS</div>\n    <div class=\"status-row\">\n      <span id=\"modeBadge\" class=\"mode-badge mode-sim\">starting</span>\n      <div class=\"status\"><span id=\"statusDot\" class=\"sim-dot\"></span><span id=\"statusTxt\">initializing...</span></div>\n      <label class=\"sound-tog\"><input type=\"checkbox\" id=\"soundOn\" checked> sound</label>\n      <button class=\"btn\" onclick=\"runScan()\">&#8635; rescan</button>\n      <button class=\"btn sim\" onclick=\"forceSim()\">demo mode</button>\n    </div>\n  </div>\n\n  <!-- MARKET STATUS + AUTO REFRESH BAR -->\n  <div class=\"refresh-bar\">\n    <span id=\"mktBadge\" class=\"mkt-closed\">&#9679; MARKET CLOSED</span>\n    <span id=\"mktTime\" style=\"color:#fff;font-weight:700\"></span>\n    <span style=\"color:#555\">|</span>\n    <span id=\"refreshLabel\">next scan in</span>\n    <div class=\"refresh-progress\"><div class=\"refresh-fill\" id=\"refreshFill\" style=\"width:100%\"></div></div>\n    <span id=\"refreshCountdown\" style=\"color:#fff;font-weight:700;min-width:35px\">\u2014</span>\n    <span style=\"color:#555\">|</span>\n    <span id=\"optRefreshLabel\" style=\"font-size:10px\">options flow refreshes every 5 min during market hours</span>\n  </div>\n\n  <div class=\"tf-bar\">\n    <span class=\"tf-label\">timeframe:</span>\n    <button class=\"tf-btn\" id=\"tf-5m\"  onclick=\"setTimeframe('5m')\">5 Min</button>\n    <button class=\"tf-btn\" id=\"tf-15m\" onclick=\"setTimeframe('15m')\">15 Min</button>\n    <button class=\"tf-btn\" id=\"tf-1h\"  onclick=\"setTimeframe('1h')\">1 Hour</button>\n    <button class=\"tf-btn\" id=\"tf-4h\"  onclick=\"setTimeframe('4h')\">4 Hour</button>\n    <button class=\"tf-btn active\" id=\"tf-1d\" onclick=\"setTimeframe('1d')\">Daily</button>\n    <button class=\"tf-btn\" id=\"tf-1wk\" onclick=\"setTimeframe('1wk')\">Weekly</button>\n    <div class=\"tf-desc\" id=\"tfDesc\">Daily candles \u00b7 13-day / 48-day MA cross \u00b7 ~3 months data</div>\n  </div>\n\n  <div id=\"infoBar\" class=\"info-bar\" style=\"display:none\"></div>\n\n  <div class=\"tabs\">\n    <div class=\"tab active\" onclick=\"switchTab('screener',this)\">screener</div>\n    <div class=\"tab\" onclick=\"switchTab('alerts',this)\">alerts <span id=\"alertCount\" style=\"font-size:10px;background:rgba(219,154,77,.25);color:#ffba5c;padding:1px 6px;border-radius:8px;margin-left:2px;font-weight:800\">0</span></div>\n    <div class=\"tab\" onclick=\"switchTab('log',this)\">signal log</div>\n  </div>\n\n  <div id=\"tab-screener\">\n    <div class=\"stats-row\">\n      <div class=\"stat\"><div class=\"stat-lbl\">scanned</div><div class=\"stat-val blue\" id=\"s-total\">\u2014</div></div>\n      <div class=\"stat\"><div class=\"stat-lbl\">bull cross</div><div class=\"stat-val green\" id=\"s-bull\">\u2014</div></div>\n      <div class=\"stat\"><div class=\"stat-lbl\">bear cross</div><div class=\"stat-val red\" id=\"s-bear\">\u2014</div></div>\n      <div class=\"stat\"><div class=\"stat-lbl\">confirmed</div><div class=\"stat-val purple\" id=\"s-conf\">\u2014</div></div>\n      <div class=\"stat\"><div class=\"stat-lbl\">timeframe</div><div class=\"stat-val blue\" style=\"font-size:15px;padding-top:4px\" id=\"s-tf\">Daily</div></div>\n    </div>\n    <div class=\"filters\">\n      <button class=\"pill a-all\" id=\"f-all\" onclick=\"setFilter('all')\">all</button>\n      <button class=\"pill\" id=\"f-bull\" onclick=\"setFilter('bull')\">&#9650; bullish</button>\n      <button class=\"pill\" id=\"f-bear\" onclick=\"setFilter('bear')\">&#9660; bearish</button>\n      <button class=\"pill\" id=\"f-conf\" onclick=\"setFilter('conf')\">&#9733; confirmed only</button>\n      <button class=\"btn primary\" onclick=\"showTopPicks()\" style=\"margin-left:auto;padding:5px 16px;font-size:12px\">&#127942; Top Picks</button>\n    </div>\n\n    <!-- TOP PICKS MODAL -->\n    <div id=\"picksOverlay\" class=\"picks-overlay\" style=\"display:none\" onclick=\"if(event.target===this)closeTopPicks()\">\n      <div class=\"picks-modal\">\n        <div class=\"picks-hdr\">\n          <div>\n            <div class=\"picks-title\">&#127942; Top Picks of the Day</div>\n            <div class=\"picks-sub\" id=\"picksSubtitle\">ranked by combined conviction score</div>\n          </div>\n          <button class=\"picks-close\" onclick=\"closeTopPicks()\">&#10005;</button>\n        </div>\n        <div id=\"picksContent\"><div class=\"picks-loading\">&#8987; Analyzing all signals...</div></div>\n      </div>\n    </div>\n\n    <!-- OPTIONS FLOW SEARCH BOX -->\n    <div style=\"display:flex;align-items:center;gap:8px;margin-bottom:.75rem;padding:10px 14px;background:#13131a;border:1px solid #2a2a3a;border-radius:10px;flex-wrap:wrap\">\n      <span style=\"font-size:11px;color:#fff;font-weight:800;letter-spacing:.07em;text-transform:uppercase;white-space:nowrap\">&#127942; Options Flow Lookup:</span>\n      <input id=\"flowSearch\" type=\"text\" placeholder=\"Enter ticker e.g. AAPL\" \n        style=\"font-size:12px;font-family:'Courier New',monospace;height:32px;padding:0 10px;background:#16161e;border:1px solid #333;color:#fff;border-radius:6px;width:160px;text-transform:uppercase;font-weight:700\"\n        onkeydown=\"if(event.key==='Enter')lookupOptionsFlow()\"\n      >\n      <button class=\"btn primary\" onclick=\"lookupOptionsFlow()\" style=\"padding:5px 14px\">&#9906; analyze flow</button>\n      <span style=\"font-size:10px;color:#888;font-weight:600\">Search any ticker for institutional options activity \u2014 not limited to screener results</span>\n    </div>\n    <div class=\"tbl-wrap\">\n      <table>\n        <thead><tr>\n          <th style=\"width:60px\"  onclick=\"sortBy('ticker')\">ticker</th>\n          <th style=\"width:68px\"  onclick=\"sortBy('price')\">price</th>\n          <th style=\"width:52px\"  onclick=\"sortBy('chg')\">chg%</th>\n          <th style=\"width:110px\" onclick=\"sortBy('signal')\">signal + tf</th>\n          <th style=\"width:65px\"  onclick=\"sortBy('vwapPos')\">vs vwap</th>\n          <th style=\"width:65px\"  onclick=\"sortBy('volume')\">volume</th>\n          <th style=\"width:88px\"  onclick=\"sortBy('strat')\">strat bar</th>\n          <th style=\"width:75px\"  onclick=\"sortBy('confirmed')\">confirmed</th>\n          <th style=\"width:55px\"  onclick=\"sortBy('score')\">score</th>\n        </tr></thead>\n        <tbody id=\"tbl\"><tr><td colspan=\"9\" style=\"text-align:center;padding:2rem;color:#aaa;font-weight:700\">loading...</td></tr></tbody>\n      </table>\n    </div>\n\n    <div class=\"chart-panel\" id=\"chartPanel\" style=\"display:none\">\n      <div class=\"chart-hdr\">\n        <div>\n          <div class=\"chart-tk\" id=\"chartTk\">\u2014</div>\n          <div class=\"chart-sub\" id=\"chartSub\"></div>\n        </div>\n        <div style=\"display:flex;flex-direction:column;align-items:flex-end;gap:10px\">\n          <div class=\"leg\">\n            <span><span class=\"leg-line\" style=\"background:#aaa\"></span>price</span>\n            <span><span class=\"leg-line\" style=\"background:#5aaeff\"></span>ma13</span>\n            <span><span class=\"leg-line\" style=\"background:#ffba5c\"></span>ma48</span>\n            <span><span class=\"leg-line\" style=\"background:#c0a0ff\"></span>vwap</span>\n            <span><span class=\"leg-line\" style=\"background:#5aff7a\"></span>obv</span>\n          </div>\n          <button class=\"btn\" id=\"addAlertBtn\" onclick=\"addAlertFromChart()\" style=\"font-size:11px;padding:4px 12px\">+ set alert</button>\n        </div>\n      </div>\n      <div class=\"tf-context\" id=\"tfContext\"></div>\n      <div class=\"conviction-card\" id=\"convCard\"></div>\n      <div class=\"score-bar-wrap\">\n        <div class=\"score-bar-lbl\"><span>conviction score</span><span id=\"scoreLabel\">0 / 5</span></div>\n        <div class=\"score-bar-bg\"><div class=\"score-bar-fill\" id=\"scoreBar\"></div></div>\n      </div>\n      <div style=\"position:relative;height:240px\"><canvas id=\"mainChart\" role=\"img\" aria-label=\"Price chart with MA13, MA48, and VWAP\">MA + VWAP chart</canvas></div>\n    </div>\n\n    <!-- OPTIONS FLOW PANEL -->\n    <div class=\"flow-panel\" id=\"flowPanel\" style=\"display:none\">\n      <div class=\"flow-hdr\">\n        <span>&#127942; Institutional Options Flow \u2014 <span id=\"flowTicker\">\u2014</span></span>\n        <span id=\"flowSentBadge\" style=\"font-size:11px;padding:3px 10px;border-radius:10px;background:#1a1a22;border:1px solid #333\">loading...</span>\n      </div>\n      <div id=\"flowContent\"><div class=\"flow-loading\">Fetching options data from Tradier...</div></div>\n    </div>\n  </div>\n\n  <div id=\"tab-alerts\" style=\"display:none\">\n    <div class=\"alert-section\">\n      <div class=\"alert-hdr\"><span>Add Price Alert</span><span style=\"font-size:11px;color:#ccc;font-weight:700\">sound + log notification</span></div>\n      <div class=\"al-form\">\n        <input id=\"al-ticker\" type=\"text\" placeholder=\"AAPL\">\n        <select id=\"al-cond\">\n          <option value=\"above\">crosses above $</option>\n          <option value=\"below\">drops below $</option>\n          <option value=\"bull_cross\">bull MA cross</option>\n          <option value=\"bear_cross\">bear MA cross</option>\n          <option value=\"vwap_conf_bull\">VWAP-confirmed bull</option>\n          <option value=\"vwap_conf_bear\">VWAP-confirmed bear</option>\n        </select>\n        <input id=\"al-price\" type=\"number\" step=\"0.01\" placeholder=\"target $\">\n        <button class=\"btn primary\" onclick=\"addAlert()\">+ add alert</button>\n      </div>\n    </div>\n    <div class=\"alert-section\">\n      <div class=\"alert-hdr\"><span>Active Alerts</span><button class=\"btn\" onclick=\"clearAllAlerts()\" style=\"font-size:11px;padding:3px 10px\">clear all</button></div>\n      <div class=\"alert-list\" id=\"alertList\"><div class=\"empty\">No alerts set</div></div>\n    </div>\n  </div>\n\n  <div id=\"tab-log\" style=\"display:none\">\n    <div class=\"notif-area\" id=\"logArea\"><div class=\"empty\">Signals appear here as detected</div></div>\n  </div>\n\n</div>\n\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.js\"></script>\n<script>\n// \u2500\u2500 YOUR LIVE BACKEND \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nconst BACKEND = window.location.origin;\n\nconst TF_CONFIG = {\n  '5m': {label:'5 Min', interval:'5m',  range:'5d',  desc:'5-min candles \u00b7 13/48-bar MA cross \u00b7 last 5 days',        maLabel:'13-bar / 48-bar'},\n  '15m':{label:'15 Min',interval:'15m', range:'1mo', desc:'15-min candles \u00b7 13/48-bar MA cross \u00b7 last 30 days',      maLabel:'13-bar / 48-bar'},\n  '1h': {label:'1 Hour',interval:'1h',  range:'3mo', desc:'1-hour candles \u00b7 13/48-bar MA cross \u00b7 last 3 months',     maLabel:'13-bar / 48-bar'},\n  '4h': {label:'4 Hour',interval:'60m', range:'6mo', desc:'4-hour candles \u00b7 13/48-bar MA cross \u00b7 last 6 months',     maLabel:'13-bar / 48-bar'},\n  '1d': {label:'Daily', interval:'1d',  range:'3mo', desc:'Daily candles \u00b7 13-day / 48-day MA cross \u00b7 last 3 months',maLabel:'13-day / 48-day'},\n  '1wk':{label:'Weekly',interval:'1wk', range:'2y',  desc:'Weekly candles \u00b7 13-week / 48-week MA cross \u00b7 2 years',   maLabel:'13-wk / 48-wk'}\n};\n\nconst TICKERS = ['AAPL','MSFT','NVDA','GOOGL','AMZN','META','TSLA','AMD','AVGO','CRM','ADBE','QCOM','JPM','BAC','V','MA','XOM','CVX','LLY','UNH','SPY','QQQ','IWM','GLD','INTC','MU','ORCL','PYPL','AMGN','GILD','BRK-B','JNJ','PG','HD','MCD','DIS','NFLX','SBUX','COST','WMT','T','VZ','PFE','ABBV','BMY','MDT','RTX','HON','CAT','GE','XLF','XLK','XLE','XLV','XLI','XLU','ARKK','DIA'];\n\nconst BASE_PRICES = {\n  'BRK-B':230,'JNJ':152,'PG':168,'HD':385,'MCD':295,'DIS':88,'NFLX':985,'SBUX':82,'COST':925,'WMT':95,'T':22,'VZ':42,'PFE':28,'ABBV':162,'BMY':51,'MDT':88,'RTX':128,'HON':218,'CAT':365,'GE':185,'XLF':45,'XLK':225,'XLE':95,'XLV':148,'XLI':138,'XLU':68,'ARKK':52,'DIA':425,\n  AAPL:276,MSFT:411,NVDA:198,GOOGL:163,AMZN:196,META:575,TSLA:285,AMD:356,\n  AVGO:431,CRM:265,ADBE:375,QCOM:184,JPM:245,BAC:42,V:345,MA:560,\n  XOM:108,CVX:148,LLY:820,UNH:298,SPY:545,QQQ:465,IWM:198,GLD:305,\n  INTC:108,MU:112,ORCL:158,PYPL:72,AMGN:265,GILD:118\n};\n\nlet allStocks=[],filtered=[],sortCol='score',sortDir=-1,curFilter='all';\nlet chartInst=null,alerts=[],logEntries=[],selectedStock=null;\nlet audioCtx=null,scanTimer=null,isSimMode=false,currentTF='1d';\n\n// \u2500\u2500 AUDIO \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction getAudio(){if(!audioCtx)audioCtx=new(window.AudioContext||window.webkitAudioContext)();return audioCtx;}\nfunction playBeep(type){\n  if(!document.getElementById('soundOn').checked)return;\n  try{\n    const a=getAudio(),o=a.createOscillator(),g=a.createGain();\n    o.connect(g);g.connect(a.destination);const t=a.currentTime;\n    if(type==='bull'){o.frequency.setValueAtTime(600,t);o.frequency.setValueAtTime(900,t+.12);}\n    else if(type==='bear'){o.frequency.setValueAtTime(500,t);o.frequency.setValueAtTime(300,t+.12);}\n    else{o.frequency.setValueAtTime(660,t);o.frequency.setValueAtTime(880,t+.07);o.frequency.setValueAtTime(1100,t+.14);}\n    g.gain.setValueAtTime(.25,t);g.gain.exponentialRampToValueAtTime(.001,t+.5);\n    o.start();o.stop(t+.5);\n  }catch(e){}\n}\n\n// \u2500\u2500 MATH \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction smaArr(arr,n){return arr.map((_,i)=>i<n-1?null:arr.slice(i-n+1,i+1).reduce((a,b)=>a+b,0)/n);}\nfunction rollingVWAP(h,l,c,v,win){\n  win=win||20;\n  return c.map((_,i)=>{\n    const s=Math.max(0,i-win+1);let tpv=0,vol=0;\n    for(let j=s;j<=i;j++){tpv+=((h[j]+l[j]+c[j])/3)*v[j];vol+=v[j];}\n    return vol>0?tpv/vol:c[i];\n  });\n}\n// OBV: On-Balance Volume \u2014 rising OBV = buying pressure, falling = selling\nfunction calcOBV(closes, volumes){\n  const obv=[0];\n  for(let i=1;i<closes.length;i++){\n    if(closes[i]>closes[i-1])obv.push(obv[i-1]+volumes[i]);\n    else if(closes[i]<closes[i-1])obv.push(obv[i-1]-volumes[i]);\n    else obv.push(obv[i-1]);\n  }\n  return obv;\n}\n// Volume trend: is volume increasing over last N bars?\nfunction volTrending(volumes, n){\n  if(volumes.length<n)return false;\n  const recent=volumes.slice(-n);\n  let up=0;\n  for(let i=1;i<recent.length;i++){if(recent[i]>recent[i-1])up++;}\n  return up>=Math.floor(n/2)+1;\n}\nfunction detectCross(closes){\n  const m13=smaArr(closes,13),m48=smaArr(closes,48),n=closes.length-1;\n  if(!m13[n]||!m48[n]||!m13[n-1]||!m48[n-1])return null;\n  let sig=null;\n  if(m13[n-1]<=m48[n-1]&&m13[n]>m48[n])sig='bull';\n  else if(m13[n-1]>=m48[n-1]&&m13[n]<m48[n])sig='bear';\n  if(!sig)return null;\n  return{sig,ma13:m13[n],ma48:m48[n],ma13arr:m13,ma48arr:m48};\n}\nfunction scoreConviction(s){\n  const{signal,price,vwap,ma13,ma48,chg,volume,avgVol,obvArr,volumes}=s;\n  let score=0;const pts=[];const av=price>vwap;\n  const n=obvArr.length;\n  // OBV rising = last OBV > OBV 3 bars ago\n  const obvRising=n>3&&obvArr[n-1]>obvArr[n-4];\n  // Volume surge = current vol > 1.5x 20-day avg (stronger threshold)\n  const volSurge=volume>avgVol*1.5;\n  // Volume trending up over last 5 bars\n  const volTrend=volTrending(volumes,5);\n\n  if(signal==='bull'){\n    const checks=[\n      {k:'price > vwap',  v:av},\n      {k:'ma13 > vwap',   v:ma13>vwap},\n      {k:'pos. bar',      v:chg>0},\n      {k:'vol surge 1.5x',v:volSurge},\n      {k:'vol trending',  v:volTrend},\n      {k:'OBV rising',    v:obvRising},\n      {k:'ma spread',     v:Math.abs(ma13-ma48)/ma48*100>0.3}\n    ];\n    checks.forEach(p=>{pts.push(p);if(p.v)score++;});\n  } else {\n    const checks=[\n      {k:'price < vwap',  v:!av},\n      {k:'ma13 < vwap',   v:ma13<vwap},\n      {k:'neg. bar',      v:chg<0},\n      {k:'vol surge 1.5x',v:volSurge},\n      {k:'vol trending',  v:volTrend},\n      {k:'OBV falling',   v:!obvRising},\n      {k:'ma spread',     v:Math.abs(ma13-ma48)/ma48*100>0.3}\n    ];\n    checks.forEach(p=>{pts.push(p);if(p.v)score++;});\n  }\n  return{score,pts,maxScore:7};\n}\n// \u2500\u2500 THE STRAT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Candle relationship vs prior candle:\n//   1  = Inside bar  (high < prev high AND low > prev low) \u2014 compression\n//   2U = Directional up (high > prev high AND low >= prev low) \u2014 bullish\n//   2D = Directional down (low < prev low AND high <= prev high) \u2014 bearish\n//   3  = Outside bar (high > prev high AND low < prev low) \u2014 expansion/reversal\nfunction calcStrat(highs, lows){\n  const n = highs.length;\n  if(n < 2) return {type:'\u2014', label:'\u2014', cls:'strat-neut'};\n  const h = highs[n-1], l = lows[n-1];\n  const ph= highs[n-2], pl= lows[n-2];\n  let type, label, cls;\n  if(h > ph && l < pl){\n    type='3'; label='3 Outside'; cls='strat-3';\n  } else if(h > ph && l >= pl){\n    type='2U'; label='2U \u25b2'; cls='strat-2u';\n  } else if(l < pl && h <= ph){\n    type='2D'; label='2D \u25bc'; cls='strat-2d';\n  } else {\n    type='1'; label='1 Inside'; cls='strat-1';\n  }\n  return{type, label, cls};\n}\n// Full Strat combo check \u2014 does the current bar align with the MA cross direction?\nfunction stratAligned(strat, signal){\n  if(signal==='bull' && (strat.type==='2U'||strat.type==='3')) return true;\n  if(signal==='bear' && (strat.type==='2D'||strat.type==='3')) return true;\n  return false;\n}\nfunction buildStock(sym,closes,highs,lows,volumes,labels,tf){\n  if(closes.length<52)return null;\n  const price=closes[closes.length-1],prev=closes[closes.length-2];\n  const chg=(price-prev)/prev*100;\n  const cross=detectCross(closes);if(!cross)return null;\n  const vwapArr=rollingVWAP(highs,lows,closes,volumes,20);\n  const vwap=vwapArr[vwapArr.length-1];\n  const strength=Math.abs(cross.ma13-cross.ma48)/cross.ma48*100;\n  const rv=volumes.slice(-20).filter(x=>x>0);\n  const avgVol=rv.length?rv.reduce((a,b)=>a+b,0)/rv.length:1;\n  const volume=volumes[volumes.length-1]||0;\n  const vwapPos=(price-vwap)/vwap*100;\n  const obvArr=calcOBV(closes,volumes);\n  const obvMax=Math.max(...obvArr.map(Math.abs))||1;\n  const obvNorm=obvArr.map(v=>v/obvMax*100);\n  const strat=calcStrat(highs,lows);\n  const stratOk=stratAligned(strat,cross.sig);\n  const stock={ticker:sym,price,chg,signal:cross.sig,ma13:cross.ma13,ma48:cross.ma48,strength,volume,avgVol,closes,highs,lows,volumes,ma13arr:cross.ma13arr,ma48arr:cross.ma48arr,vwap,vwapArr,vwapPos,labels,tf,obvArr,obvNorm,strat,stratOk};\n  const{score,pts,maxScore}=scoreConviction(stock);\n  stock.score=score;stock.pts=pts;stock.maxScore=maxScore||7;\n  stock.confirmed=score>=4; // higher threshold now that we have 7 checks\n  return stock;\n}\n\n// \u2500\u2500 SIMULATION FALLBACK \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction seededRng(seed){let s=seed;return()=>{s=(s*1664525+1013904223)&0xffffffff;return(s>>>0)/0xffffffff;};}\nfunction generateSimStock(sym,tf){\n  const seed=sym.split('').reduce((a,c)=>a+c.charCodeAt(0),0)+tf.split('').reduce((a,c)=>a+c.charCodeAt(0),0)+Math.floor(Date.now()/60000)%9999;\n  const rng=seededRng(seed);\n  const base=BASE_PRICES[sym]||100;\n  const days=80,closes=[],highs=[],lows=[],volumes=[];\n  let price=base;\n  const crossAt=days-2,signal=rng()>0.5?'bull':'bear';\n  for(let i=0;i<days;i++){\n    let drift=i<crossAt?(signal==='bull'?(rng()-.53)*.018:(rng()-.47)*.018):(signal==='bull'?(rng()-.40)*.022:(rng()-.60)*.022);\n    price=Math.max(1,price*(1+drift));\n    const range=price*(.004+rng()*.01);\n    closes.push(price);highs.push(price+range*(.4+rng()*.6));lows.push(price-range*(.4+rng()*.6));\n    volumes.push(Math.floor((rng()*80+20)*1e6));\n  }\n  const today=new Date();\n  const labels=closes.map((_,i)=>{const d=new Date(today);d.setDate(d.getDate()-(days-1-i));return d.toLocaleDateString('en-US',{month:'short',day:'numeric'});});\n  return buildStock(sym,closes,highs,lows,volumes,labels,tf);\n}\nfunction runSimulation(){\n  isSimMode=true;setModeBadge(false);\n  const tfLabel=TF_CONFIG[currentTF].label;\n  document.getElementById('statusTxt').textContent='demo mode ('+tfLabel+')';\n  showInfo('&#9888; <strong>Demo mode:</strong> Could not reach the backend server. Showing simulated signals. Click <strong>&#8635; rescan</strong> to retry live data.');\n  const prev={};allStocks.forEach(s=>prev[s.ticker]=s.signal);allStocks=[];\n  for(const sym of TICKERS){\n    const stock=generateSimStock(sym,currentTF);\n    if(stock){allStocks.push(stock);if(!prev[sym]){addLog(stock,'sim');checkAlerts(stock);}}\n  }\n  updateStats();applyFilter(curFilter);\n}\n\n// \u2500\u2500 LIVE FETCH via Railway backend \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function fetchBatch(tf){\n  const cfg=TF_CONFIG[tf];\n  try{\n    const url=`${BACKEND}/batch?symbols=${TICKERS.join(',')}&interval=${cfg.interval}&range=${cfg.range}`;\n    const ctrl=new AbortController();\n    const tid=setTimeout(()=>ctrl.abort(),60000); // 60s timeout for 58 tickers\n    const r=await fetch(url,{signal:ctrl.signal});\n    clearTimeout(tid);\n    if(!r.ok)return null;\n    const d=await r.json();\n    return d.results||null;\n  }catch(e){return null;}\n}\n\nasync function runScan(){\n  if(scanTimer){clearTimeout(scanTimer);scanTimer=null;}\n  const tfLabel=TF_CONFIG[currentTF].label;\n  document.getElementById('statusTxt').textContent='scanning ('+tfLabel+')...';\n  document.getElementById('tbl').innerHTML='<tr><td colspan=\"8\" style=\"text-align:center;padding:2rem;color:#aaa;font-weight:700\">Fetching live '+tfLabel+' data from backend...</td></tr>';\n  hideInfo();\n\n  const batchResults=await fetchBatch(currentTF);\n\n  if(!batchResults){\n    runSimulation();\n    scanTimer=setTimeout(runScan,180000);\n    return;\n  }\n\n  isSimMode=false;setModeBadge(true);hideInfo();\n  const prev={};allStocks.forEach(s=>prev[s.ticker]=s.signal);allStocks=[];\n\n  for(const sym of TICKERS){\n    const data=batchResults[sym];\n    if(!data||data.error||!data.closes)continue;\n    const stock=buildStock(sym,data.closes,data.highs,data.lows,data.volumes,data.labels,currentTF);\n    if(!stock)continue;\n    allStocks.push(stock);\n    if(!prev[sym]){addLog(stock,'detected');checkAlerts(stock);}\n    else if(prev[sym]!==stock.signal){addLog(stock,'new cross');checkAlerts(stock);}\n  }\n\n  if(!allStocks.length){\n    runSimulation();\n    showInfo('&#9432; Live data received but no MA crossovers on <strong>'+tfLabel+'</strong> right now. Showing demo signals. Try another timeframe or check back during market hours (9:30 AM\u20134 PM ET Mon\u2013Fri).');\n  } else {\n    document.getElementById('statusTxt').textContent='&#x1F7E2; LIVE ('+tfLabel+') \u2014 '+new Date().toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'});\n    updateStats();applyFilter(curFilter);\n  }\n  // Restart countdown with correct interval for market status\n  startRefreshCountdown();\n  scanTimer=setTimeout(runScan,300000);\n}\n\nfunction forceSim(){if(scanTimer){clearTimeout(scanTimer);scanTimer=null;}runSimulation();scanTimer=setTimeout(runScan,300000);}\n\nfunction setTimeframe(tf){\n  currentTF=tf;\n  Object.keys(TF_CONFIG).forEach(k=>{const el=document.getElementById('tf-'+k);if(el)el.className='tf-btn'+(k===tf?' active':'');});\n  document.getElementById('tfDesc').textContent=TF_CONFIG[tf].desc;\n  document.getElementById('s-tf').textContent=TF_CONFIG[tf].label;\n  document.getElementById('chartPanel').style.display='none';\n  document.getElementById('flowPanel').style.display='none';\n  runScan();\n}\n\nfunction setModeBadge(live){\n  const b=document.getElementById('modeBadge'),d=document.getElementById('statusDot');\n  if(live){b.className='mode-badge mode-live';b.textContent='live';d.className='live-dot';}\n  else{b.className='mode-badge mode-sim';b.textContent='simulation';d.className='sim-dot';}\n}\nfunction showInfo(msg){const el=document.getElementById('infoBar');el.innerHTML=msg;el.style.display='block';}\nfunction hideInfo(){document.getElementById('infoBar').style.display='none';}\nfunction updateStats(){\n  document.getElementById('s-total').textContent=allStocks.length;\n  document.getElementById('s-bull').textContent=allStocks.filter(s=>s.signal==='bull').length;\n  document.getElementById('s-bear').textContent=allStocks.filter(s=>s.signal==='bear').length;\n  document.getElementById('s-conf').textContent=allStocks.filter(s=>s.confirmed).length;\n}\nfunction stars(n,max){max=max||7;return'&#9733;'.repeat(n)+'&#9734;'.repeat(max-n);}\nfunction vwapLabel(s){\n  const pct=s.vwapPos.toFixed(2);\n  const good=(s.signal==='bull'&&s.vwapPos>0)||(s.signal==='bear'&&s.vwapPos<0);\n  return`<span class=\"${good?'green':'red'}\">${s.vwapPos>=0?'+':''}${pct}%</span>`;\n}\nfunction confLabel(s){\n  if(s.confirmed)return s.signal==='bull'?'<span class=\"conf-high\">&#10003; Bull Confirmed</span>':'<span class=\"conf-high\">&#10003; Bear Confirmed</span>';\n  return'<span class=\"conf-low\">Unconfirmed</span>';\n}\nfunction tfSignalLabel(s){\n  const cfg=TF_CONFIG[s.tf||'1d'];\n  const cls=s.signal==='bull'?'sig-bull':'sig-bear';\n  return`<span class=\"${cls}\">${s.signal==='bull'?'&#9650; Bull':'&#9660; Bear'}</span><span class=\"tf-tag\">${cfg.label}</span>`;\n}\nfunction buildTfContext(s){\n  const tfOrder=['5m','15m','1h','4h','1d','1wk'];\n  return tfOrder.map(tf=>{\n    const c=TF_CONFIG[tf];\n    if(tf===s.tf){\n      const cls=s.signal==='bull'?'tf-ctx-bull':'tf-ctx-bear';\n      return`<div class=\"tf-ctx-item ${cls}\"><span class=\"tf-ctx-label\">${c.label}:</span>${s.signal==='bull'?'&#9650; Golden Cross':'&#9660; Death Cross'}</div>`;\n    }\n    return`<div class=\"tf-ctx-item tf-ctx-none\"><span class=\"tf-ctx-label\">${c.label}:</span>No Signal</div>`;\n  }).join('');\n}\nfunction renderTable(){\n  const tb=document.getElementById('tbl');\n  if(!filtered.length&&allStocks.length>0){tb.innerHTML='<tr><td colspan=\"9\" style=\"text-align:center;padding:2rem;color:#aaa;font-weight:700\">No crossovers for this filter</td></tr>';return;}\n  if(!filtered.length)return;\n  tb.innerHTML=filtered.map((s,i)=>`\n    <tr onclick=\"showChart(${i})\">\n      <td class=\"tk\">${s.ticker}</td>\n      <td>$${s.price.toFixed(2)}</td>\n      <td class=\"${s.chg>=0?'green':'red'}\">${s.chg>=0?'+':''}${s.chg.toFixed(2)}%</td>\n      <td>${tfSignalLabel(s)}</td>\n      <td>${vwapLabel(s)}</td>\n      <td class=\"${s.volume>s.avgVol*1.5?'green':'amber'}\">${s.volume>1e6?(s.volume/1e6).toFixed(1)+'M':s.volume>1e3?(s.volume/1e3).toFixed(0)+'K':s.volume}</td>\n      <td><span class=\"strat-badge ${s.strat.cls} ${s.stratOk?'strat-ok':'strat-conflict'}\" title=\"${s.stratOk?'Aligns with '+s.signal+' signal':'Conflicts with '+s.signal+' signal'}\">${s.strat.label}${s.stratOk?' \u2713':' \u2717'}</span></td>\n      <td>${confLabel(s)}</td>\n      <td><span class=\"stars\" title=\"${s.score}/7\">${stars(s.score,7)}</span></td>\n    </tr>`).join('');\n}\nfunction showChart(i){\n  selectedStock=filtered[i];const s=selectedStock;\n  const cfg=TF_CONFIG[s.tf||'1d'];\n  document.getElementById('chartPanel').style.display='block';\n  document.getElementById('chartTk').textContent=s.ticker+(isSimMode?' (sim)':'');\n  document.getElementById('chartSub').textContent='$'+s.price.toFixed(2)+'  |  VWAP $'+s.vwap.toFixed(2)+'  |  '+cfg.label+' '+cfg.maLabel+' '+(s.signal==='bull'?'Golden Cross':'Death Cross')+'  |  Strat: '+s.strat.label+(s.stratOk?' \u2713':' \u2717')+'  |  Vol '+(s.volume>1e6?(s.volume/1e6).toFixed(1)+'M':s.volume.toLocaleString())+'  |  Score '+s.score+'/7';\n  document.getElementById('addAlertBtn').textContent='+ Alert for '+s.ticker;\n  document.getElementById('tfContext').innerHTML=buildTfContext(s);\n  const sc=s.score>=4?'#c0a0ff':s.score>=2?'#ffba5c':'#666';\n  document.getElementById('scoreBar').style.cssText='width:'+(s.score/7*100)+'%;background:'+sc+';height:7px;border-radius:4px;transition:width .4s';\n  document.getElementById('scoreLabel').textContent=s.score+' / 7 \u2014 '+(s.score>=5?'High Conviction':s.score>=3?'Moderate':'Low');\n  const bull=s.signal==='bull';\n  document.getElementById('convCard').innerHTML=s.pts.map(p=>`<div class=\"cv-item\"><div class=\"cv-lbl\">${p.k}</div><div class=\"cv-val ${p.v?(bull?'green':'red'):'amber'}\">${p.v?'&#10003;':'&#10007;'}</div></div>`).join('');\n  if(chartInst)chartInst.destroy();\n\n  // Dual axis: price/MA/VWAP on y (left), OBV normalized on y1 (right)\n  chartInst=new Chart(document.getElementById('mainChart'),{\n    type:'line',\n    data:{labels:s.labels,datasets:[\n      {label:'Price',data:s.closes,  borderColor:'#aaa',   borderWidth:1.5,pointRadius:0,tension:.3,yAxisID:'y'},\n      {label:'MA13', data:s.ma13arr, borderColor:'#5aaeff',borderWidth:2.5,pointRadius:0,tension:.3,yAxisID:'y'},\n      {label:'MA48', data:s.ma48arr, borderColor:'#ffba5c',borderWidth:2.5,pointRadius:0,tension:.3,borderDash:[5,3],yAxisID:'y'},\n      {label:'VWAP', data:s.vwapArr, borderColor:'#c0a0ff',borderWidth:2,  pointRadius:0,tension:.3,borderDash:[3,2],yAxisID:'y'},\n      {label:'OBV',  data:s.obvNorm, borderColor:'#5aff7a',borderWidth:1.5,pointRadius:0,tension:.3,borderDash:[2,2],yAxisID:'y1',fill:false}\n    ]},\n    options:{responsive:true,maintainAspectRatio:false,interaction:{mode:'index',intersect:false},\n      plugins:{legend:{display:false},tooltip:{backgroundColor:'#1a1a22',borderColor:'#444',borderWidth:1,titleColor:'#fff',bodyColor:'#fff',callbacks:{label:ctx=>{\n        if(ctx.dataset.label==='OBV')return` OBV: ${ctx.raw!=null?ctx.raw.toFixed(1):'\u2014'}`;\n        return` ${ctx.dataset.label}: $${ctx.raw!=null?ctx.raw.toFixed(2):'\u2014'}`;\n      }}}},\n      scales:{\n        x:{ticks:{maxTicksLimit:8,color:'#ddd',font:{size:11,weight:'bold'}},grid:{color:'rgba(255,255,255,.05)'}},\n        y:{ticks:{color:'#ddd',font:{size:11,weight:'bold'},callback:v=>'$'+v.toFixed(0)},grid:{color:'rgba(255,255,255,.05)'}},\n        y1:{position:'right',ticks:{color:'#5aff7a',font:{size:10},callback:v=>v.toFixed(0)},grid:{drawOnChartArea:false},title:{display:true,text:'OBV',color:'#5aff7a',font:{size:10}}}\n      }\n    }\n  });\n  document.getElementById('chartPanel').scrollIntoView({behavior:'smooth',block:'nearest'});\n  // Load options flow for this ticker\n  loadOptionsFlow(s.ticker);\n}\n\n// \u2500\u2500 OPTIONS FLOW SEARCH \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function lookupOptionsFlow(){\n  const input = document.getElementById('flowSearch');\n  const ticker = input.value.toUpperCase().trim();\n  if(!ticker){ input.focus(); return; }\n\n  // Show the flow panel and price panel\n  const flowPanel  = document.getElementById('flowPanel');\n  const chartPanel = document.getElementById('chartPanel');\n  flowPanel.style.display='block';\n  document.getElementById('flowTicker').textContent=ticker;\n  document.getElementById('flowContent').innerHTML='<div class=\"flow-loading\">&#8987; Fetching options flow for '+ticker+'...</div>';\n  document.getElementById('flowSentBadge').textContent='loading...';\n  document.getElementById('flowSentBadge').style.cssText='font-size:11px;padding:3px 10px;border-radius:10px;background:#1a1a22;border:1px solid #333;color:#aaa';\n\n  // Scroll to flow panel\n  flowPanel.scrollIntoView({behavior:'smooth',block:'nearest'});\n\n  // Also fetch price chart for this ticker\n  try{\n    const priceRes = await fetch(`${BACKEND}/quote?symbol=${ticker}&interval=1d&range=3mo`);\n    const priceData = await priceRes.json();\n    if(!priceData.error && priceData.closes && priceData.closes.length > 1){\n      chartPanel.style.display='block';\n      document.getElementById('chartTk').textContent=ticker+' \u2014 Options Flow Lookup';\n      document.getElementById('chartSub').textContent='Price chart (last 3 months) \u00b7 Click a screener row for full MA/VWAP analysis';\n      document.getElementById('addAlertBtn').textContent='+ Alert for '+ticker;\n      document.getElementById('tfContext').innerHTML='';\n      document.getElementById('convCard').innerHTML='';\n      document.getElementById('scoreBar').style.width='0%';\n      document.getElementById('scoreLabel').textContent='\u2014';\n      if(chartInst)chartInst.destroy();\n      chartInst=new Chart(document.getElementById('mainChart'),{\n        type:'line',\n        data:{labels:priceData.labels,datasets:[\n          {label:'Price',data:priceData.closes,borderColor:'#5aaeff',borderWidth:2,pointRadius:0,tension:.3}\n        ]},\n        options:{responsive:true,maintainAspectRatio:false,interaction:{mode:'index',intersect:false},\n          plugins:{legend:{display:false},tooltip:{backgroundColor:'#1a1a22',borderColor:'#444',borderWidth:1,titleColor:'#fff',bodyColor:'#fff',callbacks:{label:ctx=>` Price: $${ctx.raw!=null?ctx.raw.toFixed(2):'\u2014'}`}}},\n          scales:{\n            x:{ticks:{maxTicksLimit:8,color:'#ddd',font:{size:11,weight:'bold'}},grid:{color:'rgba(255,255,255,.05)'}},\n            y:{ticks:{color:'#ddd',font:{size:11,weight:'bold'},callback:v=>'$'+v.toFixed(0)},grid:{color:'rgba(255,255,255,.05)'}}\n          }\n        }\n      });\n    }\n  }catch(e){}\n\n  // Load options flow\n  await loadOptionsFlow(ticker);\n  input.value='';\n}\n\n// \u2500\u2500 OPTIONS FLOW \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nconst optionsCache = {};\nasync function loadOptionsFlow(ticker){\n  const panel  = document.getElementById('flowPanel');\n  const content= document.getElementById('flowContent');\n  const tickEl = document.getElementById('flowTicker');\n  const sentEl = document.getElementById('flowSentBadge');\n\n  panel.style.display='block';\n  tickEl.textContent=ticker;\n  sentEl.textContent='loading...';\n  sentEl.style.cssText='font-size:11px;padding:3px 10px;border-radius:10px;background:#1a1a22;border:1px solid #333;color:#aaa';\n  content.innerHTML='<div class=\"flow-loading\">&#8987; Fetching options flow from Tradier...</div>';\n\n  // Use cache if fresh (< 5 min)\n  if(optionsCache[ticker] && Date.now()-optionsCache[ticker].ts < 300000){\n    renderOptionsFlow(optionsCache[ticker].data);\n    return;\n  }\n\n  try{\n    const r = await fetch(`${BACKEND}/options?symbol=${ticker}`);\n    const data = await r.json();\n    if(data.error){\n      content.innerHTML=`<div class=\"flow-loading\" style=\"color:#ff5a5a\">&#9888; ${data.error}</div>`;\n      return;\n    }\n    optionsCache[ticker]={data,ts:Date.now()};\n    renderOptionsFlow(data);\n  }catch(e){\n    content.innerHTML='<div class=\"flow-loading\" style=\"color:#ff5a5a\">Could not load options data</div>';\n  }\n}\n\nfunction renderOptionsFlow(d){\n  const sentEl=document.getElementById('flowSentBadge');\n  const content=document.getElementById('flowContent');\n\n  // Sentiment badge\n  const sentColor=d.sentiment==='bullish'?'#5aff7a':d.sentiment==='bearish'?'#ff5a5a':'#ffba5c';\n  const sentBg=d.sentiment==='bullish'?'rgba(77,184,77,.15)':d.sentiment==='bearish'?'rgba(255,90,90,.15)':'rgba(219,154,77,.15)';\n  const sentBorder=d.sentiment==='bullish'?'rgba(77,184,77,.4)':d.sentiment==='bearish'?'rgba(255,90,90,.4)':'rgba(219,154,77,.4)';\n  const sentIcon=d.sentiment==='bullish'?'&#129345;':d.sentiment==='bearish'?'&#129344;':'&#9889;';\n  sentEl.innerHTML=`${sentIcon} ${d.sentiment.toUpperCase()} FLOW`;\n  sentEl.style.cssText=`font-size:11px;padding:3px 10px;border-radius:10px;background:${sentBg};border:1px solid ${sentBorder};color:${sentColor};font-weight:800`;\n\n  // PC ratio color\n  const pc=parseFloat(d.pcRatio);\n  const pcClass=isNaN(pc)?'pc-neut':pc<0.7?'pc-bull':pc>1.2?'pc-bear':'pc-neut';\n\n  // Flow score bar\n  const flowPct=(d.flowScore/3*100).toFixed(0);\n  const flowColor=d.flowScore>=2?'#5aff7a':d.flowScore===1?'#ffba5c':'#ff5a5a';\n\n  // Unusual options table\n  const unusualRows=d.topUnusual&&d.topUnusual.length\n    ?d.topUnusual.map(u=>`\n      <tr>\n        <td>${u.exp}</td>\n        <td>$${u.strike}</td>\n        <td><span class=\"opt-tag opt-${u.type}\">${u.type.toUpperCase()}</span></td>\n        <td class=\"${u.type==='call'?'green':'red'}\">${u.volume?.toLocaleString()}</td>\n        <td class=\"amber\">${u.volRatio}</td>\n        <td class=\"${u.type==='call'?'green':'red'}\">${u.ratio}</td>\n      </tr>`).join('')\n    :'<tr><td colspan=\"6\" style=\"text-align:center;color:#aaa;padding:12px\">No unusual activity detected</td></tr>';\n\n  content.innerHTML=`\n    <div class=\"flow-grid\">\n      <div class=\"flow-stat\">\n        <div class=\"flow-lbl\">put/call ratio</div>\n        <div class=\"flow-val ${pcClass}\">${d.pcRatio}</div>\n      </div>\n      <div class=\"flow-stat\">\n        <div class=\"flow-lbl\">call volume</div>\n        <div class=\"flow-val green\">${d.totalCallVol?.toLocaleString()||'\u2014'}</div>\n      </div>\n      <div class=\"flow-stat\">\n        <div class=\"flow-lbl\">put volume</div>\n        <div class=\"flow-val red\">${d.totalPutVol?.toLocaleString()||'\u2014'}</div>\n      </div>\n      <div class=\"flow-stat\">\n        <div class=\"flow-lbl\">unusual alerts</div>\n        <div class=\"flow-val amber\">${d.unusualCount||0}</div>\n      </div>\n    </div>\n    <div class=\"sentiment-bar\">\n      <span class=\"sent-label\">Flow Score</span>\n      <div class=\"sent-track\"><div class=\"sent-fill\" style=\"width:${flowPct}%;background:${flowColor}\"></div></div>\n      <span style=\"color:${flowColor};font-size:11px;min-width:30px\">${d.flowScore}/3</span>\n    </div>\n    <div style=\"font-size:11px;color:#ccc;margin-bottom:6px;font-weight:700\">&#9889; Unusual Options Activity (top sweeps)</div>\n    <table class=\"unusual-table\">\n      <thead><tr>\n        <th>expiry</th><th>strike</th><th>type</th><th>volume</th><th>vs avg</th><th>vol/oi</th>\n      </tr></thead>\n      <tbody>${unusualRows}</tbody>\n    </table>\n    <div style=\"font-size:10px;color:#555;margin-top:8px;font-weight:600\">\n      P/C &lt; 0.7 = bullish flow &nbsp;|&nbsp; P/C &gt; 1.2 = bearish flow &nbsp;|&nbsp; Vol/OI &gt; 0.5 = sweep activity\n    </div>`;\n}\nfunction addLog(s,type){\n  const cfg=TF_CONFIG[s.tf||'1d'];\n  const now=new Date().toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit',second:'2-digit'});\n  logEntries.unshift({ticker:s.ticker,signal:s.signal,price:s.price,type:'['+cfg.label+'] '+type+(s.confirmed?' + VWAP confirmed':''),score:s.score,time:now});\n  if(logEntries.length>60)logEntries.pop();\n  renderLog();playBeep(s.confirmed?'confirmed':s.signal);\n}\nfunction renderLog(){\n  const el=document.getElementById('logArea');\n  if(!logEntries.length){el.innerHTML='<div class=\"empty\">No signals yet</div>';return;}\n  el.innerHTML=logEntries.slice(0,30).map(e=>`\n    <div class=\"notif ${e.signal}\">\n      <span><strong>${e.ticker}</strong> \u2014 ${e.signal==='bull'?'&#9650;':'&#9660;'} ${e.type} at $${e.price.toFixed(2)} &middot; Score ${e.score}/5</span>\n      <span class=\"notif-time\">${e.time}</span>\n    </div>`).join('');\n}\nfunction setFilter(f){\n  curFilter=f;\n  ['all','bull','bear','conf'].forEach(x=>document.getElementById('f-'+x).className='pill'+(x===f?' a-'+f:''));\n  applyFilter(f);\n}\nfunction applyFilter(f){\n  filtered=f==='all'?[...allStocks]:f==='conf'?allStocks.filter(s=>s.confirmed):allStocks.filter(s=>s.signal===f);\n  sortTable();\n}\nfunction sortBy(col){\n  if(sortCol===col)sortDir*=-1;else{sortCol=col;sortDir=-1;}sortTable();\n}\nfunction sortTable(){\n  filtered.sort((a,b)=>{\n    let av,bv;\n    if(sortCol==='strat'){av=a.strat?a.strat.type:'';bv=b.strat?b.strat.type:'';}\n    else{av=a[sortCol];bv=b[sortCol];}\n    if(av==null)av=0;if(bv==null)bv=0;\n    if(typeof av==='string')return sortDir*av.localeCompare(bv);\n    return sortDir*(av-bv);\n  });\n  renderTable();\n}\nfunction addAlertFromChart(){\n  if(!selectedStock)return;\n  document.getElementById('al-ticker').value=selectedStock.ticker;\n  document.getElementById('al-price').value=selectedStock.price.toFixed(2);\n  switchTab('alerts',document.querySelectorAll('.tab')[1]);\n}\nfunction addAlert(){\n  const ticker=document.getElementById('al-ticker').value.toUpperCase().trim();\n  const cond=document.getElementById('al-cond').value;\n  const price=parseFloat(document.getElementById('al-price').value);\n  if(!ticker)return;\n  alerts.push({id:Date.now(),ticker,cond,price:price||null,triggered:false});\n  document.getElementById('al-ticker').value='';document.getElementById('al-price').value='';\n  renderAlerts();\n}\nfunction removeAlert(id){alerts=alerts.filter(a=>a.id!==id);renderAlerts();}\nfunction clearAllAlerts(){alerts=[];renderAlerts();}\nfunction condLabel(a){return{above:`above $${a.price?.toFixed(2)||''}`,below:`below $${a.price?.toFixed(2)||''}`,bull_cross:'Bull MA Cross',bear_cross:'Bear MA Cross',vwap_conf_bull:'VWAP-Confirmed Bull',vwap_conf_bear:'VWAP-Confirmed Bear'}[a.cond]||a.cond;}\nfunction renderAlerts(){\n  document.getElementById('alertCount').textContent=alerts.length;\n  const el=document.getElementById('alertList');\n  if(!alerts.length){el.innerHTML='<div class=\"empty\">No alerts set</div>';return;}\n  el.innerHTML=alerts.map(a=>`\n    <div class=\"al-item ${a.triggered?'triggered':''}\">\n      <span style=\"font-weight:800;font-size:14px;min-width:50px\">${a.ticker}</span>\n      <span style=\"font-size:12px;color:#ddd;flex:1\">${condLabel(a)}</span>\n      <span style=\"font-size:11px;color:${a.triggered?'#ffba5c':'#888'};font-weight:700\">${a.triggered?'&#10003; Triggered':'Watching'}</span>\n      <button class=\"btn\" onclick=\"removeAlert(${a.id})\" style=\"font-size:11px;padding:2px 10px;margin-left:8px\">x</button>\n    </div>`).join('');\n}\nfunction checkAlerts(s){\n  let hit=false;\n  alerts.forEach(a=>{\n    if(a.triggered||a.ticker!==s.ticker)return;\n    let fired=false;\n    if(a.cond==='above'&&s.price>=a.price)fired=true;\n    if(a.cond==='below'&&s.price<=a.price)fired=true;\n    if(a.cond==='bull_cross'&&s.signal==='bull')fired=true;\n    if(a.cond==='bear_cross'&&s.signal==='bear')fired=true;\n    if(a.cond==='vwap_conf_bull'&&s.signal==='bull'&&s.confirmed)fired=true;\n    if(a.cond==='vwap_conf_bear'&&s.signal==='bear'&&s.confirmed)fired=true;\n    if(fired){a.triggered=true;hit=true;logEntries.unshift({ticker:s.ticker,signal:'price',price:s.price,type:'ALERT: '+condLabel(a),score:s.score,time:new Date().toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit',second:'2-digit'})});renderLog();playBeep('confirmed');}\n  });\n  if(hit)renderAlerts();\n}\nfunction switchTab(name,el){\n  ['screener','alerts','log'].forEach(t=>document.getElementById('tab-'+t).style.display=t===name?'block':'none');\n  document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));\n  el.classList.add('active');\n}\n\n// \u2500\u2500 TOP PICKS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nconst TOP_N = 10; // show top 10\n\nasync function showTopPicks(){\n  const overlay = document.getElementById('picksOverlay');\n  const content = document.getElementById('picksContent');\n  const subtitle = document.getElementById('picksSubtitle');\n  overlay.style.display = 'flex';\n  document.body.style.overflow = 'hidden';\n\n  if(!allStocks.length){\n    content.innerHTML = '<div class=\"picks-empty\">No signals found yet \u2014 run a scan first</div>';\n    return;\n  }\n\n  content.innerHTML = '<div class=\"picks-loading\">&#8987; Scoring all signals...</div>';\n\n  // Score each stock across all indicators\n  const scored = await Promise.all(allStocks.map(async s => {\n    let totalScore = 0;\n    const reasons = [];\n\n    // MA Cross strength (0-2)\n    const maScore = s.strength > 1 ? 2 : s.strength > 0.5 ? 1 : 0;\n    totalScore += maScore;\n    if(maScore > 0) reasons.push('Strong MA cross');\n\n    // VWAP confirmed (0-2)\n    if(s.confirmed){ totalScore += 2; reasons.push('VWAP confirmed'); }\n    else if(Math.abs(s.vwapPos) < 0.5){ totalScore += 1; }\n\n    // Volume surge (0-2)\n    if(s.volume > s.avgVol * 2){ totalScore += 2; reasons.push('2x vol surge'); }\n    else if(s.volume > s.avgVol * 1.5){ totalScore += 1; reasons.push('Vol surge'); }\n\n    // OBV aligned (0-1)\n    if(s.obvArr && s.obvArr.length > 4){\n      const n = s.obvArr.length;\n      const obvRising = s.obvArr[n-1] > s.obvArr[n-4];\n      if((s.signal==='bull' && obvRising)||(s.signal==='bear' && !obvRising)){\n        totalScore += 1; reasons.push('OBV aligned');\n      }\n    }\n\n    // Strat aligned (0-2)\n    if(s.stratOk){\n      if(s.strat.type==='2U'||s.strat.type==='2D'){ totalScore += 1; reasons.push('Strat '+s.strat.type); }\n      if(s.strat.type==='3'){ totalScore += 2; reasons.push('Strat 3 Outside'); }\n    }\n\n    // Options flow (0-3) \u2014 fetch if not cached\n    let flowScore = 0;\n    try{\n      if(optionsCache[s.ticker] && Date.now()-optionsCache[s.ticker].ts < 600000){\n        flowScore = optionsCache[s.ticker].data.flowScore || 0;\n      } else {\n        const r = await fetch(BACKEND+'/options?symbol='+s.ticker);\n        const d = await r.json();\n        if(!d.error){ optionsCache[s.ticker]={data:d,ts:Date.now()}; flowScore=d.flowScore||0; }\n      }\n    }catch(e){}\n\n    // Align flow with signal direction\n    if(s.signal==='bull' && flowScore >= 2){ totalScore += 3; reasons.push('Bullish options flow'); }\n    else if(s.signal==='bull' && flowScore === 1){ totalScore += 1; }\n    else if(s.signal==='bear' && flowScore === 0){ totalScore += 3; reasons.push('Bearish options flow'); }\n    else if(s.signal==='bear' && flowScore === 1){ totalScore += 1; }\n\n    return { ...s, totalScore, reasons, flowScore, maxTotal: 13 };\n  }));\n\n  // Sort by total score descending\n  scored.sort((a,b) => b.totalScore - a.totalScore);\n  const top = scored.slice(0, TOP_N);\n\n  subtitle.textContent = 'top '+Math.min(top.length, TOP_N)+' of '+allStocks.length+' signals \u2014 '+TF_CONFIG[currentTF].label+' timeframe \u2014 '+new Date().toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'});\n\n  if(!top.length){\n    content.innerHTML = '<div class=\"picks-empty\">No signals to rank \u2014 try rescanning</div>';\n    return;\n  }\n\n  content.innerHTML = top.map((s,i) => {\n    const rank = i+1;\n    const rankLabel = rank===1?'&#127947;':rank===2?'&#129352;':rank===3?'&#129353;':'#'+rank;\n    const pct = (s.totalScore/s.maxTotal*100).toFixed(0);\n    const barColor = pct>=70?'#5aff7a':pct>=45?'#ffba5c':'#5aaeff';\n    const bull = s.signal==='bull';\n    const sigCls = bull?'sig-bull':'sig-bear';\n    const sigTxt = bull?'&#9650; Bull Cross':'&#9660; Bear Cross';\n    const cfg = TF_CONFIG[s.tf||'1d'];\n\n    // Key indicator pills\n    const inds = [\n      {k:'VWAP', v:s.confirmed},\n      {k:'Vol', v:s.volume>s.avgVol*1.5},\n      {k:'OBV', v:s.obvArr&&s.obvArr.length>4&&((bull&&s.obvArr[s.obvArr.length-1]>s.obvArr[s.obvArr.length-4])||(!bull&&s.obvArr[s.obvArr.length-1]<s.obvArr[s.obvArr.length-4]))},\n      {k:'Strat '+s.strat.type, v:s.stratOk},\n      {k:'Flow', v:(bull&&s.flowScore>=2)||(!bull&&s.flowScore===0)}\n    ];\n\n    const cardClass = 'pick-card rank-'+Math.min(rank,4);\n    const cardClick = 'closeTopPicks();showChart('+allStocks.findIndex(x=>x.ticker===s.ticker)+')';\n    const indHtml = inds.map(function(ind){return '<span class=\"pick-ind '+(ind.v?'ind-pass':'ind-fail')+'\">'+(ind.v?'checkmark':'cross')+' '+ind.k+'</span>';}).join('').replace(/checkmark/g,'&#10003;').replace(/cross/g,'&#10007;');\n    const reasonTxt = s.reasons.length ? s.reasons.join(' &middot; ') : 'Basic MA crossover signal';\n    return '<div class=\"'+cardClass+'\" onclick=\"'+cardClick+'\">'\n      +'<div class=\"pick-row1\">'\n      +'<span class=\"pick-rank\">'+rankLabel+'</span>'\n      +'<span class=\"pick-ticker\">'+s.ticker+'</span>'\n      +'<span class=\"pick-price\">$'+s.price.toFixed(2)+'</span>'\n      +'<span class=\"pick-signal-badge '+sigCls+'\">'+sigTxt+'</span>'\n      +'<span class=\"pick-tf\">'+cfg.label+'</span>'\n      +'<span style=\"margin-left:auto;font-size:11px;color:'+barColor+';font-weight:800\">'+s.totalScore+'/'+s.maxTotal+'</span>'\n      +'</div>'\n      +'<div class=\"pick-score-bar\"><div class=\"pick-score-fill\" style=\"width:'+pct+'%;background:'+barColor+'\"></div></div>'\n      +'<div class=\"pick-indicators\">'+indHtml+'</div>'\n      +'<div class=\"pick-reason\">'+reasonTxt+'</div>'\n      +'</div>';\n  }).join('');\n}\n\nfunction closeTopPicks(){\n  document.getElementById('picksOverlay').style.display='none';\n  document.body.style.overflow='';\n}\n\n// \u2500\u2500 MARKET HOURS + AUTO REFRESH ENGINE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nconst SCAN_INTERVAL_OPEN   = 5 * 60;  // 5 min during market hours\nconst SCAN_INTERVAL_CLOSED = 15 * 60; // 15 min outside hours\nconst FLOW_INTERVAL        = 5 * 60;  // options flow refresh every 5 min\nlet refreshSecondsLeft = SCAN_INTERVAL_OPEN;\nlet refreshTick = null;\nlet flowRefreshTimer = null;\n\nfunction isMarketOpen(){\n  const now = new Date();\n  // Convert to ET\n  const et = new Date(now.toLocaleString('en-US', {timeZone:'America/New_York'}));\n  const day = et.getDay(); // 0=Sun, 6=Sat\n  const h = et.getHours(), m = et.getMinutes();\n  const mins = h * 60 + m;\n  if(day === 0 || day === 6) return 'closed';\n  if(mins >= 570 && mins < 630) return 'pre';    // 9:30\u201310:30 pre-market indicator\n  if(mins >= 570 && mins < 960) return 'open';   // 9:30 AM \u2013 4:00 PM\n  if(mins >= 480 && mins < 570) return 'pre';    // 8:00\u20139:30 pre-market\n  return 'closed';\n}\n\nfunction updateMarketBadge(){\n  const badge = document.getElementById('mktBadge');\n  const timeEl = document.getElementById('mktTime');\n  const status = isMarketOpen();\n  const now = new Date();\n  const etTime = now.toLocaleTimeString('en-US',{timeZone:'America/New_York',hour:'2-digit',minute:'2-digit',second:'2-digit'});\n\n  if(status==='open'){\n    badge.className='mkt-open';\n    badge.textContent='&#9679; MARKET OPEN';\n    timeEl.textContent='ET '+etTime;\n  } else if(status==='pre'){\n    badge.className='mkt-pre';\n    badge.textContent='&#9679; PRE-MARKET';\n    timeEl.textContent='ET '+etTime;\n  } else {\n    badge.className='mkt-closed';\n    badge.textContent='&#9679; MARKET CLOSED';\n    timeEl.textContent='ET '+etTime;\n  }\n  return status;\n}\n\nfunction startRefreshCountdown(){\n  if(refreshTick) clearInterval(refreshTick);\n  const status = updateMarketBadge();\n  const interval = status==='open' ? SCAN_INTERVAL_OPEN : SCAN_INTERVAL_CLOSED;\n  refreshSecondsLeft = interval;\n\n  refreshTick = setInterval(()=>{\n    updateMarketBadge();\n    refreshSecondsLeft--;\n    // Update countdown display\n    const m = Math.floor(refreshSecondsLeft/60);\n    const s = refreshSecondsLeft % 60;\n    document.getElementById('refreshCountdown').textContent = m+'m '+String(s).padStart(2,'0')+'s';\n    // Update progress bar\n    const pct = (refreshSecondsLeft / interval * 100).toFixed(1);\n    document.getElementById('refreshFill').style.width = pct+'%';\n\n    if(refreshSecondsLeft <= 0){\n      runScan();\n      refreshSecondsLeft = interval;\n    }\n  }, 1000);\n}\n\nfunction startFlowAutoRefresh(){\n  if(flowRefreshTimer) clearInterval(flowRefreshTimer);\n  flowRefreshTimer = setInterval(()=>{\n    const status = isMarketOpen();\n    if(status === 'open' && selectedStock){\n      // Silently refresh options flow for current stock\n      delete optionsCache[selectedStock.ticker];\n      loadOptionsFlow(selectedStock.ticker);\n    }\n  }, FLOW_INTERVAL * 1000);\n}\n\ndocument.getElementById('tfDesc').textContent=TF_CONFIG['1d'].desc;\nrenderAlerts();\nrunScan();\nstartRefreshCountdown();\nstartFlowAutoRefresh();\n</script>\n</body>\n</html>\n";

